#include<bits/stdc++.h>
#define LL long long
#define UInt unsigned int
#define ULL unsigned long long
#define LD long double
#define pii pair<int,int>
#define pLL pair<LL,LL>
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 1005;
const LL Mod = 1e9+7;
string L,R;
LL n,Qian,dp[N][2][2][2][11][11],Ans;
LL read(){
    LL su=0,pp=1;char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')pp=-1;ch=getchar();}
    while(ch>='0'&&ch<='9'){su=su*10+ch-'0';ch=getchar();}
    return su*pp;
}
void UP(int &x){if(x==0)x++;x++;return;}
int main(){
    cin>>L>>R;//输入
    Qian=R.size()-L.size();//计算有多少个前导零
    for(char &u:L)u=(char)(u+1);//处理
    for(char &u:R)u=(char)(u+1);//处理
    while(L.size()<R.size())L="0"+L;//补全前导零
    memset(dp,0,sizeof(dp));//清空 DP 数组
    dp[0][0][0][0][0][0]=1;//给定初值
    n=R.size();//计算数字的位数
    for(int i=0;i<n;i++)for(int x=0;x<2;x++)//枚举
    for(int y=0;y<2;y++)for(int s=0;s<2;s++)//枚举
    for(int u=0;u<=10;u++)for(int k=0;k<=10;k++)//枚举
    for(int j=(x?1:L[i]-'0');j<=(y?10:R[i]-'0');/*j++*/UP(j)){//枚举
        int nx=(x||(j>(L[i]-'0')));//计算 new_x
        int ny=(y||(j<(R[i]-'0')));//计算 new_y
        int ns=s;if(u&&j&&u==j)ns=1;if(k&&j&&k==j)ns=1;//计算 new_s
        dp[i+1][nx][ny][ns][k][j]+=dp[i][x][y][s][u][k];//转移
        dp[i+1][nx][ny][ns][k][j]%=Mod;
    }
    Ans=0;//清零 Ans
    for(int x=0;x<2;x++)for(int y=0;y<2;y++)
        for(int u=1;u<=10;u++)for(int k=1;k<=10;k++)
            Ans=(Ans+dp[n][x][y][1][u][k])%Mod;//累加答案
    cout<<Ans<<"\n";//输出答案
    return 0;
}
